import type { I18nOptions } from '../i18n';

import { getI18n as getI18nCore, setI18n } from '@nordic/core-context';

import { I18n } from '../i18n';
import { throwI18nNotInitializedError } from '../error';

export function getI18n() {
  const currentI18n = getI18nCore<I18n | I18nOptions>();

  if (__DEV__ && !currentI18n) {
    throwI18nNotInitializedError();
  }

  if (currentI18n instanceof I18n) {
    return currentI18n;
  }

  const i18n = currentI18n && new I18n(currentI18n);

  setI18n(i18n);

  return i18n!;
}
